// build-shopify-pages-navigation — Validate Pages/Nav Input
// Validates store_blueprint (pages + navigation) and runtime_config; extracts shop_url.
// Safety rules: no deletes, idempotent upsert by handle, new pages never auto-published.

const input = $input.first().json;

const runtimeConfig  = input.runtime_config   || {};
const storeBlueprint = input.store_blueprint   || null;
const contentStrategy = input.content_strategy || {};
// project_id is top-level; runtime_config does not carry it directly
const projectId      = input.project_id        || runtimeConfig.project_id || null;

if (!projectId) {
  throw new Error('MISSING_RUNTIME_CONFIG: build-shopify-pages-navigation requires project_id (top-level) or runtime_config.project_id');
}

if (!storeBlueprint) {
  throw new Error('MISSING_ARTIFACT: store_blueprint is required but was not found in trigger input');
}

const pages      = storeBlueprint.pages      || [];
const navigation = storeBlueprint.navigation || [];

if (pages.length === 0 && navigation.length === 0) {
  throw new Error('INVALID_BLUEPRINT: store_blueprint.pages and store_blueprint.navigation are both empty — nothing to deploy');
}

// resolve-runtime-config uses keys: shopify_shop_url, shopify_api_version
const shopUrl    = runtimeConfig.shopify_shop_url    || runtimeConfig.shop_url    || runtimeConfig.STORE_OS_SHOPIFY_SHOP_URL    || null;
const apiVersion = runtimeConfig.shopify_api_version || runtimeConfig.api_version || runtimeConfig.STORE_OS_SHOPIFY_API_VERSION || '2025-01';

if (!shopUrl) {
  throw new Error(
    'MISSING_CONFIG: shop_url not found in runtime_config. ' +
    'Ensure STORE_OS_SHOPIFY_SHOP_URL is set in env or passed as smoke_test_config.STORE_OS_SHOPIFY_SHOP_URL'
  );
}

const shopDomain  = shopUrl.replace(/^https?:\/\//, '').replace(/\/$/, '');
const shopifyBase = 'https://' + shopDomain + '/admin/api/' + apiVersion;

// Page strategy snippet from content_strategy for body generation
const pageStrategy = (contentStrategy.page_strategy || {});

console.log(
  `build-shopify-pages-navigation: project=${projectId}, shop=${shopDomain}, ` +
  `pages=${pages.length}, navigation=${navigation.length}`
);

return [{
  json: {
    project_id:       projectId,
    runtime_config:   runtimeConfig,
    store_blueprint:  storeBlueprint,
    content_strategy: contentStrategy,
    page_strategy:    pageStrategy,
    shop_url:         shopUrl,
    shop_domain:      shopDomain,
    api_version:      apiVersion,
    shopify_base:     shopifyBase,
    pages_count:      pages.length,
    navigation_count: navigation.length,
  },
}];

// build-shopify-pages-navigation — Build Upsert Plan
// Compares existing Shopify pages and link_lists against store_blueprint.
// Produces one action item per resource: {resource, action, handle, url, body, ...}
// Safety: no deletes, new pages published: false (hidden until manually published).

const items = $input.all();

// Pull validated config from Validate Pages/Nav Input node
const validated      = $node['Validate Pages/Nav Input'].json;
const blueprint      = validated.store_blueprint;
const shopifyBase    = validated.shopify_base;
const projectId      = validated.project_id;
const pageStrategy   = validated.page_strategy || {};

// Parse Merge Fetch Results — one item has pages, other has link_lists
let existingPages     = [];
let existingLinkLists = [];

for (const item of items) {
  // continueOnFail: true on Fetch nodes means errors arrive as items with item.json.error
  // Treat fetch errors as empty arrays (credential may lack read_content scope — creates only)
  if (item.json.error) {
    console.log('Fetch node returned error (treating as empty):', JSON.stringify(item.json.error).slice(0, 200));
    continue;
  }
  if (item.json.pages !== undefined)      existingPages     = item.json.pages      || [];
  if (item.json.link_lists !== undefined) existingLinkLists = item.json.link_lists || [];
}

// Index existing by handle for O(1) lookup
const pagesByHandle     = {};
for (const p of existingPages)     { if (p.handle) pagesByHandle[p.handle] = p; }
const linkListsByHandle = {};
for (const l of existingLinkLists) { if (l.handle) linkListsByHandle[l.handle] = l; }

console.log(
  `Build Upsert Plan: existing pages=${existingPages.length}, existing link_lists=${existingLinkLists.length}`
);

// ── Link type mapping helper ───────────────────────────────────────────────
function mapLinkType(linkType, target) {
  // Maps store_blueprint navigation link_type to Shopify link_list link type and URL.
  const t = (linkType || '').toLowerCase();
  if (t === 'frontpage' || t === 'home' || t === 'homepage') {
    return { type: 'frontpage', url: '/' };
  } else if (t === 'page') {
    return { type: 'page', url: '/pages/' + (target || '') };
  } else if (t === 'collection') {
    return { type: 'collection', url: '/collections/' + (target || '') };
  } else if (t === 'product') {
    return { type: 'product', url: '/products/' + (target || '') };
  } else if (t === 'blog') {
    return { type: 'blog', url: '/blogs/' + (target || '') };
  }
  // Default: http link using target as URL if it looks like a URL, else ignore
  return { type: 'http', url: target || '/' };
}

// ── Page body generation helper ────────────────────────────────────────────
function generatePageHtml(page) {
  const safeText = (s) => String(s || '').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  const title   = safeText(page.title || '');
  const purpose = safeText(page.purpose || '');
  const seo     = safeText(page.seo_focus || '');
  let html = '';
  if (purpose) html += '<p>' + purpose + '</p>';
  if (seo && seo !== purpose) html += '<p>' + seo + '</p>';
  return html || '<p>Page content coming soon.</p>';
}

const actions = [];

// ── Pages ─────────────────────────────────────────────────────────────────
for (const page of (blueprint.pages || [])) {
  const handle = page.handle || page.title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
  const bodyHtml = page.body_html || generatePageHtml(page);

  const pageBody = {
    page: {
      title:      page.title,
      handle:     handle,
      body_html:  bodyHtml,
      author:     'store-os',
      published:  false,  // Safety: never auto-publish — must be reviewed before publishing
    },
  };

  if (pagesByHandle[handle]) {
    const existingId = pagesByHandle[handle].id;
    actions.push({
      resource:        'page',
      action:          'update',
      handle:          handle,
      shopify_id:      existingId,
      url:             shopifyBase + '/pages/' + existingId + '.json',
      body:            pageBody,
      blueprint_title: page.title,
    });
  } else {
    actions.push({
      resource:        'page',
      action:          'create',
      handle:          handle,
      shopify_id:      null,
      url:             shopifyBase + '/pages.json',
      body:            pageBody,
      blueprint_title: page.title,
    });
  }
}

// ── Navigation / Link Lists ────────────────────────────────────────────────
for (const menu of (blueprint.navigation || [])) {
  const handle = menu.menu_handle || menu.handle || (menu.title || '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');

  // Build Shopify link_list links array from blueprint items
  const links = (menu.items || []).map((item) => {
    const mapped = mapLinkType(item.link_type, item.target);
    return {
      title: item.label || item.title || item.target || '',
      type:  mapped.type,
      url:   mapped.url,
    };
  });

  const linkListBody = {
    link_list: {
      title:  menu.title,
      handle: handle,
      links:  links,
    },
  };

  if (linkListsByHandle[handle]) {
    const existingId = linkListsByHandle[handle].id;
    actions.push({
      resource:        'link_list',
      action:          'update',
      handle:          handle,
      shopify_id:      existingId,
      url:             shopifyBase + '/link_lists/' + existingId + '.json',
      body:            linkListBody,
      blueprint_title: menu.title,
    });
  } else {
    actions.push({
      resource:        'link_list',
      action:          'create',
      handle:          handle,
      shopify_id:      null,
      url:             shopifyBase + '/link_lists.json',
      body:            linkListBody,
      blueprint_title: menu.title,
    });
  }
}

console.log(
  `Build Upsert Plan: planned actions=${actions.length} ` +
  `(creates=${actions.filter(a=>a.action==='create').length}, ` +
  `updates=${actions.filter(a=>a.action==='update').length})`
);

if (actions.length === 0) {
  return [{ json: { action: 'noop', resource: 'none', handle: null, url: null, body: null, blueprint_title: null, shopify_id: null } }];
}

return actions.map(a => ({ json: a }));

// build-shopify-pages-navigation — Compile Deployment Summary
// Aggregates HTTP results from Create Resource and Update Resource nodes.
// Counts by statusCode and resource type (page vs link_list).
// Returns PHASE_7B2_COMPLETE with deployment summary.

const results = $input.all();

const validated  = $node['Validate Pages/Nav Input'].json;
const projectId  = validated.project_id;
const shopDomain = validated.shop_domain;
const blueprint  = validated.store_blueprint;

let pagesCreated      = 0;
let pagesUpdated      = 0;
let navigationCreated = 0;
let navigationUpdated = 0;
const errors   = [];
const warnings = [];

for (const item of results) {
  const d = item.json;

  // noop sentinel
  if (d.action === 'noop') {
    warnings.push('No pages/navigation actions were planned — store_blueprint may be empty or all resources already match');
    continue;
  }

  const statusCode = d.statusCode || 0;
  const body       = d.body || d;

  if (statusCode >= 400 || d.error) {
    const errMsg = (body.errors ? JSON.stringify(body.errors) : null)
      || d.message
      || `HTTP ${statusCode} error`;
    errors.push({
      resource: d._resource || 'unknown',
      handle:   d._handle   || 'unknown',
      status:   statusCode,
      message:  errMsg,
    });
    continue;
  }

  const isPage     = !!(body.page);
  const isLinkList = !!(body.link_list);

  if (statusCode === 201) {
    if (isPage)     pagesCreated++;
    if (isLinkList) navigationCreated++;
  } else if (statusCode === 200) {
    if (isPage)     pagesUpdated++;
    if (isLinkList) navigationUpdated++;
  } else {
    warnings.push(
      `Unexpected HTTP ${statusCode} for ${ isPage ? 'page' : isLinkList ? 'link_list' : 'resource' }`
    );
  }
}

const totalActioned = pagesCreated + pagesUpdated + navigationCreated + navigationUpdated;
const totalErrors   = errors.length;
const terminalStatus = totalErrors > 0 && totalActioned === 0
  ? 'PHASE_7B2_FAILED'
  : totalErrors > 0
    ? 'PHASE_7B2_PARTIAL'
    : 'PHASE_7B2_COMPLETE';

console.log(
  `Compile Deployment Summary: status=${terminalStatus}, ` +
  `pages_created=${pagesCreated}, pages_updated=${pagesUpdated}, ` +
  `navigation_created=${navigationCreated}, navigation_updated=${navigationUpdated}, ` +
  `errors=${totalErrors}`
);

return [{
  json: {
    status:               terminalStatus,
    project_id:           projectId,
    shop_url:             shopDomain,
    completed_at:         new Date().toISOString(),

    pages_created:        pagesCreated,
    pages_updated:        pagesUpdated,
    navigation_created:   navigationCreated,
    navigation_updated:   navigationUpdated,

    errors:   errors,
    warnings: warnings,

    blueprint_summary: {
      pages_in_blueprint:      (blueprint.pages      || []).length,
      navigation_in_blueprint: (blueprint.navigation || []).length,
    },

    safety_notes: [
      'No Shopify resources were deleted — only create and update operations were performed',
      'All new pages were created with published: false — not visible until manually published',
    ],
  },
}];
